<?php require '_header.php'; $items=read_json('blogs'); if(isset($_GET['delete'])){ $items=array_values(array_filter($items,fn($x)=>$x['slug']!==$_GET['delete'])); write_json('blogs',$items); header('Location: blogs.php'); exit; } ?><div class="admin-head"><h1>Blogs</h1><a class="btn primary" href="blog-form.php">Add Blog</a></div><table class="admin-table"><tr><th>Title</th><th>Category</th><th>Date</th><th>Actions</th></tr><?php foreach($items as $x): ?><tr><td><?=e($x['title'])?></td><td><?=e($x['category'])?></td><td><?=e($x['date'])?></td><td><a href="blog-form.php?slug=<?=e($x['slug'])?>">Edit</a> | <a onclick="return confirm('Delete blog?')" href="blogs.php?delete=<?=e($x['slug'])?>">Delete</a></td></tr><?php endforeach; ?></table><?php require '_footer.php'; ?>
